def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    def extract_checklist_items(slide) -> list:
        items = []
        for shape in slide.shapes:
            if shape.has_text_frame:
                for paragraph in shape.text_frame.paragraphs:
                    text = paragraph.text.strip()
                    if text:
                        items.append(text)
        return items

    orig_prs = Presentation(original_ppt_path)
    mod_prs = Presentation(modified_ppt_path)
    orig_slide = orig_prs.slides[7]
    mod_slide = mod_prs.slides[7]
    orig_items = set(extract_checklist_items(orig_slide))
    mod_items = set(extract_checklist_items(mod_slide))
    modified = set()
    for o in orig_items:
        if o not in mod_items:
            for m in mod_items:
                # If there is a similar item, but not identical, consider as modified
                if o.lower() in m.lower() or m.lower() in o.lower():
                    modified.add((o, m))
    if modified:
        return f"Checklist items modified: {modified}", 0.0
    return "No checklist items modified.", 1.0

