    prompt = "Does the slide image show a checklist rendered as a two-column layout? Reply 'yes' or 'no'."
    result = vlm_call(prompt, [img], temperature=0.0, max_tokens=10)
    if 'yes' in result.lower():
        return "Checklist is rendered as a two-column layout.", 1.0
    return f"VLM response: {result}", 0.0

