    # Use ppt_diff to check modifications outside slide 8
    modified_ids = set()
    for (s1, s2) in ppt_diff.modified_slides:
        if s1.slide_number != 8:
            modified_ids.add(s1.slide_number)
    for s in ppt_diff.added_slides:
        if s.slide_number != 8:
            modified_ids.add(s.slide_number)
    for s in ppt_diff.removed_slides:
        if s.slide_number != 8:
            modified_ids.add(s.slide_number)
    if modified_ids:
        return f"Slides modified other than slide 8: {sorted(modified_ids)}", 0.0
    return "No content or layout changes on other slides.", 1.0

